<script setup lang="ts">
import { computed, onMounted, reactive, ref } from "vue";
import type { MerchantMemberView, StaffInvitationView, StoreProfileView, UserRole } from "@moecraft/shared";
import { apiRequest } from "../../../api";
import { useLocale } from "../../../i18n";
const props=defineProps<{roles:UserRole[];section:"store"|"team"}>();const{t}=useLocale();const loading=ref(true),busy=ref(false),message=ref(""),error=ref("");const members=ref<MerchantMemberView[]>([]),invitations=ref<StaffInvitationView[]>([]);const isOwner=computed(()=>props.roles.includes("MERCHANT_OWNER"));const invite=reactive({username:"",role:"STAFF" as "OWNER"|"STAFF"});const form=reactive({name:"",slug:"",logoFileId:"",bannerFileId:"",description:"",customerServiceEmail:"",customerServicePhone:"",isOpen:true,returnAddress:{recipient:"",phone:"",country:"中国",province:"",city:"",district:"",addressLine:"",postalCode:""}});
function feedback(ok:string){message.value=ok;error.value=""}function fail(){error.value=t("store.error");message.value=""}function fill(store:StoreProfileView|null){if(store)Object.assign(form,{...store,returnAddress:store.returnAddress??form.returnAddress})}
async function load(){loading.value=true;try{const[store,team,pending]=await Promise.all([apiRequest<StoreProfileView|null>("/merchant/store"),apiRequest<MerchantMemberView[]>("/merchant/members"),apiRequest<StaffInvitationView[]>("/staff-invitations/mine")]);fill(store);members.value=team;invitations.value=pending}catch{fail()}finally{loading.value=false}}
async function save(){busy.value=true;try{const payload={name:form.name,slug:form.slug,logoFileId:form.logoFileId||undefined,bannerFileId:form.bannerFileId||undefined,description:form.description||undefined,customerServiceEmail:form.customerServiceEmail||undefined,customerServicePhone:form.customerServicePhone||undefined,isOpen:form.isOpen,returnAddress:{...form.returnAddress,postalCode:form.returnAddress.postalCode||undefined}};await apiRequest("/merchant/store",{method:"PUT",body:JSON.stringify(payload)});feedback(t("store.saved"))}catch{fail()}finally{busy.value=false}}
async function media(kind:"logoFileId"|"bannerFileId",files:FileList|null){const file=files?.[0];if(!file)return;try{const asset=await apiRequest<{id:string}>("/files",{method:"POST",body:JSON.stringify({purpose:"store-media",fileName:file.name,mimeType:file.type,sizeBytes:file.size})});form[kind]=asset.id}catch{fail()}}
async function sendInvite(){busy.value=true;try{await apiRequest("/merchant/invitations",{method:"POST",body:JSON.stringify(invite)});invite.username="";feedback(t("store.invited"))}catch{fail()}finally{busy.value=false}}
async function setRole(member:MerchantMemberView,role:"OWNER"|"STAFF"){try{await apiRequest(`/merchant/members/${member.id}`,{method:"PATCH",body:JSON.stringify({role})});await load();feedback(t("store.memberUpdated"))}catch{fail()}}
async function remove(member:MerchantMemberView){try{await apiRequest(`/merchant/members/${member.id}`,{method:"DELETE"});await load();feedback(t("store.memberRemoved"))}catch{fail()}}
async function accept(id:string){try{await apiRequest(`/staff-invitations/${id}/accept`,{method:"POST"});await load();feedback(t("store.invitationAccepted"))}catch{fail()}}
onMounted(load);
</script>
<template><section class="store-page content-scroll" :class="`section-${props.section}`"><div class="page-shell"><header><div><span>STORE OPERATIONS</span><h1>{{t('store.title')}}</h1><p>{{t('store.subtitle')}}</p></div><label class="switch"><input v-model="form.isOpen" :disabled="!isOwner" type="checkbox"><i/><b>{{t(form.isOpen?'store.open':'store.closed')}}</b></label></header><p v-if="message||error" class="feedback" :class="{error}">{{message||error}}</p><div v-if="loading" class="loading">{{t('common.loading')}}</div><template v-else><div v-if="invitations.length" class="invites"><div><h2>{{t('store.invitations')}}</h2><p v-for="item in invitations" :key="item.id">{{item.merchantName}} · {{item.role}}</p></div><button v-for="item in invitations" :key="item.id" @click="accept(item.id)">{{t('store.accept')}}</button></div><div class="layout"><form class="panel profile" @submit.prevent="save"><h2>{{t('store.profile')}}</h2><div class="grid"><label><span>{{t('store.name')}}</span><input v-model="form.name" :disabled="!isOwner" required minlength="2"></label><label><span>{{t('store.slug')}}</span><input v-model="form.slug" :disabled="!isOwner" required pattern="[a-z0-9]+(?:-[a-z0-9]+)*"></label><label class="full"><span>{{t('store.description')}}</span><textarea v-model="form.description" :disabled="!isOwner" rows="4"/></label><label><span>{{t('store.serviceEmail')}}</span><input v-model="form.customerServiceEmail" :disabled="!isOwner" type="email"></label><label><span>{{t('store.servicePhone')}}</span><input v-model="form.customerServicePhone" :disabled="!isOwner"></label></div><h3>{{t('store.returnAddress')}}</h3><div class="grid address"><label><span>{{t('store.recipient')}}</span><input v-model="form.returnAddress.recipient" :disabled="!isOwner" required></label><label><span>{{t('store.phone')}}</span><input v-model="form.returnAddress.phone" :disabled="!isOwner" required></label><label><span>{{t('store.country')}}</span><input v-model="form.returnAddress.country" :disabled="!isOwner" required></label><label><span>{{t('store.province')}}</span><input v-model="form.returnAddress.province" :disabled="!isOwner" required></label><label><span>{{t('store.city')}}</span><input v-model="form.returnAddress.city" :disabled="!isOwner" required></label><label><span>{{t('store.district')}}</span><input v-model="form.returnAddress.district" :disabled="!isOwner" required></label><label class="full"><span>{{t('store.addressLine')}}</span><input v-model="form.returnAddress.addressLine" :disabled="!isOwner" required></label><label><span>{{t('store.postalCode')}}</span><input v-model="form.returnAddress.postalCode" :disabled="!isOwner"></label></div><button v-if="isOwner" class="primary" :disabled="busy">{{t('store.save')}}</button></form><aside class="panel team"><h2>{{t('store.members')}}</h2><form v-if="isOwner" class="invite-form" @submit.prevent="sendInvite"><input v-model="invite.username" required :placeholder="t('store.inviteUsername')"><select v-model="invite.role"><option value="STAFF">{{t('store.staff')}}</option><option value="OWNER">{{t('store.owner')}}</option></select><button>{{t('store.invite')}}</button></form><p v-if="!members.length">{{t('store.emptyMembers')}}</p><article v-for="member in members" :key="member.id"><span>{{member.displayName.slice(0,1)}}</span><div><b>{{member.displayName}}</b><small>@{{member.username}}</small></div><select :value="member.role" :disabled="!isOwner" @change="setRole(member,($event.target as HTMLSelectElement).value as 'OWNER'|'STAFF')"><option value="OWNER">{{t('store.owner')}}</option><option value="STAFF">{{t('store.staff')}}</option></select><button v-if="isOwner" class="remove" @click="remove(member)">{{t('store.remove')}}</button></article></aside></div></template></div></section></template>
<style scoped>.section-store .team{display:none}.section-team .profile{display:none}.section-team .layout{grid-template-columns:minmax(0,760px);justify-content:center}.store-page{background:var(--shell-bg);color:var(--text)}.page-shell{width:min(1260px,100%);margin:auto}header{display:flex;align-items:center;justify-content:space-between;padding:28px 32px;margin-bottom:20px;border:1px solid var(--border);border-radius:17px;background:linear-gradient(120deg,var(--accent-soft),var(--surface) 55%)}header span{color:var(--accent);font-size:10px;font-weight:700;letter-spacing:.16em}h1{margin:7px 0;font-size:30px}header p{margin:0;color:var(--text-muted);font-size:12px}.switch{display:flex;align-items:center;gap:9px}.switch input{display:none}.switch i{position:relative;width:42px;height:23px;border-radius:20px;background:var(--border)}.switch i:after{position:absolute;width:17px;height:17px;left:3px;top:3px;border-radius:50%;background:white;content:"";transition:.2s}.switch input:checked+i{background:var(--success)}.switch input:checked+i:after{transform:translateX(19px)}.switch b{font-size:11px}.layout{display:grid;grid-template-columns:minmax(0,1.45fr) minmax(320px,.55fr);gap:20px}.panel,.invites{padding:26px;border:1px solid var(--border);border-radius:15px;background:var(--surface);box-shadow:var(--shadow)}.panel h2{margin:0 0 20px}.panel h3{padding-top:22px;margin-top:25px;border-top:1px solid var(--border)}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}.grid .full{grid-column:1/-1}label{display:grid;gap:7px}label span{color:var(--text-secondary);font-size:11px}input,textarea,select{padding:11px;border:1px solid var(--border);border-radius:8px;background:var(--surface-raised);color:var(--text)}.primary,.invite-form button,.invites button{padding:11px 16px;border:0;border-radius:8px;background:var(--accent);color:white;cursor:pointer}.profile>.primary{margin-top:22px}.invite-form{display:grid;grid-template-columns:1fr 90px auto;gap:7px;padding-bottom:16px;border-bottom:1px solid var(--border)}.team article{display:grid;grid-template-columns:36px 1fr 82px auto;align-items:center;gap:10px;padding:13px 0;border-bottom:1px solid var(--border)}.team article>span{display:grid;width:34px;height:34px;place-items:center;border-radius:9px;background:var(--accent-soft);color:var(--accent);font-weight:700}.team article div{display:grid}.team article small{color:var(--text-muted)}.remove{border:0;background:transparent;color:var(--danger);cursor:pointer}.feedback,.loading,.invites{margin-bottom:18px}.feedback{padding:12px;border-radius:9px;background:var(--success-soft);color:var(--success)}.feedback.error{background:var(--danger-soft);color:var(--danger)}.invites{display:flex;align-items:center;justify-content:space-between}.invites h2{margin:0}.invites p{margin:4px 0;color:var(--text-muted)}@media(max-width:900px){.layout{grid-template-columns:1fr}}@media(max-width:650px){header{align-items:flex-start;flex-direction:column;gap:18px;padding:22px}.grid{grid-template-columns:1fr}.grid .full{grid-column:auto}.invite-form{grid-template-columns:1fr}.team article{grid-template-columns:36px 1fr}.team article select,.team article button{grid-column:2}}</style>

